from collections import deque
def largest_component(grid,color):
    n=len(grid)
    m=len(grid[0])
    visited=[[False]*m for _ in range(n)]
    max_sz=0
    for i in range(n):
        for j in range(m):
            if grid[i][j]==color and not visited[i][j]:
                q=deque([(i,j)])
                visited[i][j]=True
                size=0
                while q:
                    y,x=q.popleft()
                    size+=1
                    for dy,dx in [(1,0),(-1,0),(0,1),(0,-1)]:
                        ny, nx = y+dy, x+dx
                        if 0<=ny<n and 0<=nx<m and not visited[ny][nx] and grid[ny][nx]==color:
                            visited[ny][nx]=True
                            q.append((ny,nx))
                if size>max_sz:
                    max_sz=size
    return max_sz
