def components_count(grid,color):
    n=len(grid); m=len(grid[0])
    visited=[[False]*m for _ in range(n)]
    count=0
    for i in range(n):
        for j in range(m):
            if grid[i][j]==color and not visited[i][j]:
                count+=1
                q=[(i,j)]
                visited[i][j]=True
                while q:
                    y,x=q.pop()
                    for dy,dx in [(1,0),(-1,0),(0,1),(0,-1)]:
                        ny, nx=y+dy, x+dx
                        if 0<=ny<n and 0<=nx<m and not visited[ny][nx] and grid[ny][nx]==color:
                            visited[ny][nx]=True
                            q.append((ny,nx))
    return count
