def bounding_box(grid,color):
    ys=[i for i in range(10) for j in range(10) if grid[i][j]==color]
    xs=[j for i in range(10) for j in range(10) if grid[i][j]==color]
    if not ys: return None
    return min(ys),max(ys),min(xs),max(xs)
